export type EditorState = {
  html: string;
  css: string;
  javascript: string;
};

const STORAGE_KEY = "webpad:state";

export function readStoredState(): EditorState | null {
  if (typeof window === "undefined") return null;
  try {
    const raw = window.localStorage.getItem(STORAGE_KEY);
    if (!raw) return null;
    const parsed = JSON.parse(raw) as Partial<EditorState>;
    if (
      typeof parsed.html === "string" &&
      typeof parsed.css === "string" &&
      typeof parsed.javascript === "string"
    ) {
      return { html: parsed.html, css: parsed.css, javascript: parsed.javascript };
    }
    return null;
  } catch {
    return null;
  }
}

export function writeStoredState(state: EditorState): void {
  if (typeof window === "undefined") return;
  try {
    window.localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  } catch {
    // ignore quota / disabled storage
  }
}

import LZString from "lz-string";
import type { EditorState } from "./storage";

export function encodeStateToHash(state: EditorState): string {
  return LZString.compressToEncodedURIComponent(JSON.stringify(state));
}

export function decodeStateFromHash(hash: string): EditorState | null {
  if (!hash) return null;
  const raw = hash.startsWith("#") ? hash.slice(1) : hash;
  if (!raw) return null;
  try {
    const decompressed = LZString.decompressFromEncodedURIComponent(raw);
    if (!decompressed) return null;
    const parsed = JSON.parse(decompressed) as Partial<EditorState>;
    if (
      typeof parsed.html === "string" &&
      typeof parsed.css === "string" &&
      typeof parsed.javascript === "string"
    ) {
      return { html: parsed.html, css: parsed.css, javascript: parsed.javascript };
    }
    return null;
  } catch {
    return null;
  }
}

export function writeHash(state: EditorState): void {
  if (typeof window === "undefined") return;
  const encoded = encodeStateToHash(state);
  const newHash = `#${encoded}`;
  if (window.location.hash !== newHash) {
    history.replaceState(null, "", `${window.location.pathname}${window.location.search}${newHash}`);
  }
}

const CONSOLE_INTERCEPT = `
(function(){
  var send = function(level, args){
    try {
      var safe = Array.prototype.slice.call(args).map(function(a){
        if (a instanceof Error) return { __error: true, name: a.name, message: a.message, stack: a.stack };
        try { JSON.stringify(a); return a; } catch(e) { return String(a); }
      });
      window.parent.postMessage({ type: 'console', level: level, args: safe }, '*');
    } catch(e) {}
  };
  var origLog = console.log, origWarn = console.warn, origError = console.error;
  console.log = function(){ send('log', arguments); origLog.apply(console, arguments); };
  console.warn = function(){ send('warn', arguments); origWarn.apply(console, arguments); };
  console.error = function(){ send('error', arguments); origError.apply(console, arguments); };
  window.addEventListener('error', function(e){
    send('error', [e.message + (e.filename ? ' (' + e.filename + ':' + e.lineno + ':' + e.colno + ')' : '')]);
  });
  window.addEventListener('unhandledrejection', function(e){
    var reason = e.reason;
    send('error', ['Unhandled promise rejection: ' + (reason && reason.message ? reason.message : String(reason))]);
  });
})();
`;

export function buildSrcdoc(html: string, css: string, js: string): string {
  return `<!DOCTYPE html><html><head><meta charset="UTF-8"/><style>${css}</style></head><body>${html}<script>${CONSOLE_INTERCEPT}<\/script><script>${js}<\/script></body></html>`;
}

"use client";

export type ConsoleLevel = "log" | "warn" | "error";

export interface ConsoleMessage {
  id: number;
  level: ConsoleLevel;
  args: unknown[];
}

interface Props {
  messages: ConsoleMessage[];
  onClear: () => void;
}

const LEVEL_STYLES: Record<ConsoleLevel, string> = {
  log: "text-gray-100",
  warn: "text-yellow-400",
  error: "text-red-400",
};

function formatArg(arg: unknown): string {
  if (arg === null) return "null";
  if (arg === undefined) return "undefined";
  if (typeof arg === "string") return arg;
  if (typeof arg === "number" || typeof arg === "boolean") return String(arg);
  if (typeof arg === "object" && arg !== null && "__error" in arg) {
    const e = arg as { name?: string; message?: string };
    return `${e.name ?? "Error"}: ${e.message ?? ""}`;
  }
  try {
    return JSON.stringify(arg);
  } catch {
    return String(arg);
  }
}

export default function ConsolePanel({ messages, onClear }: Props) {
  return (
    <div className="h-48 shrink-0 border-t border-gray-700 bg-gray-950 flex flex-col">
      <div className="flex items-center justify-between px-3 py-1.5 border-b border-gray-700 bg-gray-900 shrink-0">
        <span className="text-xs font-medium text-gray-300 uppercase tracking-wide">Console</span>
        <button
          onClick={onClear}
          className="text-xs text-gray-400 hover:text-white transition-colors"
        >
          Clear
        </button>
      </div>
      <div className="flex-1 min-h-0 overflow-y-auto font-mono text-xs">
        {messages.length === 0 ? (
          <div className="px-3 py-2 text-gray-500">No output yet.</div>
        ) : (
          messages.map((msg) => (
            <div
              key={msg.id}
              className={`px-3 py-1 border-b border-gray-800 whitespace-pre-wrap break-words ${LEVEL_STYLES[msg.level]}`}
            >
              {msg.args.map(formatArg).join(" ")}
            </div>
          ))
        )}
      </div>
    </div>
  );
}

"use client";

import dynamic from "next/dynamic";
import { useState, useEffect, useCallback, useRef } from "react";
import PreviewFrame from "./PreviewFrame";
import ConsolePanel, { ConsoleMessage, ConsoleLevel } from "./ConsolePanel";
import { buildSrcdoc } from "@/lib/buildSrcdoc";
import { readStoredState, writeStoredState, type EditorState } from "@/lib/storage";
import { decodeStateFromHash, writeHash } from "@/lib/urlState";

const EditorPanel = dynamic(() => import("./EditorPanel"), { ssr: false });

const DEFAULT_HTML = `<h1>Hello, webpad!</h1>
<p>Edit the panels on the left to see changes here.</p>
<button onclick="handleClick()">Click me</button>`;

const DEFAULT_CSS = `body {
  font-family: sans-serif;
  padding: 2rem;
  background: #f9fafb;
  color: #111;
}

h1 {
  color: #2563eb;
}

button {
  margin-top: 1rem;
  padding: 0.5rem 1.25rem;
  background: #2563eb;
  color: white;
  border: none;
  border-radius: 6px;
  cursor: pointer;
  font-size: 1rem;
}

button:hover {
  background: #1d4ed8;
}`;

const DEFAULT_JS = `function handleClick() {
  alert('Hello from webpad!');
}`;

type Lang = "html" | "css" | "javascript";

const DEFAULT_STATE: EditorState = {
  html: DEFAULT_HTML,
  css: DEFAULT_CSS,
  javascript: DEFAULT_JS,
};

function resolveInitialState(): EditorState {
  if (typeof window === "undefined") return DEFAULT_STATE;
  const fromHash = decodeStateFromHash(window.location.hash);
  if (fromHash) return fromHash;
  const fromStorage = readStoredState();
  if (fromStorage) return fromStorage;
  return DEFAULT_STATE;
}

export default function Playground() {
  const [values, setValues] = useState<EditorState>(DEFAULT_STATE);
  const [srcdoc, setSrcdoc] = useState(() =>
    buildSrcdoc(DEFAULT_HTML, DEFAULT_CSS, DEFAULT_JS)
  );
  const [hydrated, setHydrated] = useState(false);
  const [messages, setMessages] = useState<ConsoleMessage[]>([]);
  const [copied, setCopied] = useState(false);
  const messageIdRef = useRef(0);

  // Hydrate from URL hash ŌåÆ localStorage ŌåÆ defaults after mount (avoids SSR mismatch).
  useEffect(() => {
    const initial = resolveInitialState();
    setValues(initial);
    setSrcdoc(buildSrcdoc(initial.html, initial.css, initial.javascript));
    setHydrated(true);
  }, []);

  const rebuild = useCallback((next: EditorState) => {
    setSrcdoc(buildSrcdoc(next.html, next.css, next.javascript));
    setMessages([]);
  }, []);

  // Debounced rebuild + persistence (localStorage + URL hash).
  useEffect(() => {
    if (!hydrated) return;
    const id = setTimeout(() => {
      rebuild(values);
    }, 500);
    writeStoredState(values);
    writeHash(values);
    return () => clearTimeout(id);
  }, [values, hydrated, rebuild]);

  // Receive console messages from sandboxed iframe.
  useEffect(() => {
    function handler(event: MessageEvent) {
      const data = event.data;
      if (!data || typeof data !== "object") return;
      if (data.type !== "console") return;
      const level = data.level as ConsoleLevel;
      if (level !== "log" && level !== "warn" && level !== "error") return;
      const args = Array.isArray(data.args) ? (data.args as unknown[]) : [];
      messageIdRef.current += 1;
      setMessages((prev) => [...prev, { id: messageIdRef.current, level, args }]);
    }
    window.addEventListener("message", handler);
    return () => window.removeEventListener("message", handler);
  }, []);

  // Cmd+Enter / Ctrl+Enter triggers immediate rebuild.
  useEffect(() => {
    function onKeyDown(e: KeyboardEvent) {
      if ((e.metaKey || e.ctrlKey) && e.key === "Enter") {
        e.preventDefault();
        rebuild(values);
      }
    }
    document.addEventListener("keydown", onKeyDown);
    return () => document.removeEventListener("keydown", onKeyDown);
  }, [values, rebuild]);

  function handleChange(lang: Lang, value: string) {
    setValues((prev) => ({ ...prev, [lang]: value }));
  }

  async function handleCopyLink() {
    try {
      await navigator.clipboard.writeText(window.location.href);
      setCopied(true);
      setTimeout(() => setCopied(false), 1500);
    } catch {
      // ignore
    }
  }

  function handleClearConsole() {
    setMessages([]);
  }

  return (
    <div className="flex h-screen bg-gray-950">
      <div className="flex-1 min-w-0 border-r border-gray-700">
        <EditorPanel values={values} onChange={handleChange} />
      </div>
      <div className="flex-1 min-w-0 flex flex-col">
        <div className="flex items-center justify-between px-3 py-1.5 border-b border-gray-700 bg-gray-900 shrink-0">
          <span className="text-xs text-gray-400">
            <kbd className="px-1.5 py-0.5 rounded bg-gray-800 text-gray-300 font-mono">Ōīś</kbd>
            <span className="mx-1">+</span>
            <kbd className="px-1.5 py-0.5 rounded bg-gray-800 text-gray-300 font-mono">Enter</kbd>
            <span className="ml-2">to run</span>
          </span>
          <button
            onClick={handleCopyLink}
            className="text-xs px-2 py-1 rounded bg-blue-600 hover:bg-blue-500 text-white transition-colors"
          >
            {copied ? "Copied!" : "Copy link"}
          </button>
        </div>
        <div className="flex-1 min-h-0">
          <PreviewFrame srcdoc={srcdoc} />
        </div>
        <ConsolePanel messages={messages} onClear={handleClearConsole} />
      </div>
    </div>
  );
}

